`timescale 1ns / 1ps

module testbench();
    reg in;
    wire out;
    inverter inverter(in, out);

    initial begin
        $dumpfile(`DUMP_FILE_NAME);
        $dumpvars;
    end

    initial begin
        $sdf_annotate(`SDF_FILE_NAME, testbench.inverter);
    end

    initial begin
        in = 0; #1
        in = 1; #1 
        in = 0; #1 
        $finish;
    end
endmodule
